/** @odoo-module **/
/**
 * CoolCold Theme — Navbar Active Menu Tracker for Odoo 18
 * Auto-generated by generate_theme.py
 *
 * 1. Parent menu highlight (cc-active-parent): uses Odoo menu data to match URL action ID
 * 2. Child item highlight (cc-active-item): marks active item when dropdown opens
 */

import { NavBar } from "@web/webclient/navbar/navbar";
import { patch } from "@web/core/utils/patch";
import { useEffect } from "@odoo/owl";

function getActiveActionId() {
    const url = location.href;
    const match = url.match(/action[=-](\d+)/);
    return match ? match[1] : null;
}

function matchesAction(href, actionId) {
    if (!href || !actionId) return false;
    return href.endsWith("/action-" + actionId) ||
           href.includes("/action-" + actionId + "#") ||
           href.includes("/action-" + actionId + "?");
}

function searchMenuTree(sections, actionId, getHref) {
    for (const section of sections) {
        if (matchesAction(getHref(section), actionId)) return section.id;
        if (section.childrenTree) {
            for (const child of section.childrenTree) {
                if (matchesAction(getHref(child), actionId)) return section.id;
                if (child.childrenTree) {
                    for (const gc of child.childrenTree) {
                        if (matchesAction(getHref(gc), actionId)) return section.id;
                    }
                }
            }
        }
    }
    return null;
}

patch(NavBar.prototype, {
    setup() {
        super.setup(...arguments);
        useEffect(() => { this._ccHighlightParent(); });
    },

    _ccHighlightParent() {
        const actionId = getActiveActionId();
        const navbar = document.querySelector(".o_menu_sections");
        if (!navbar) return;

        navbar.querySelectorAll(".cc-active-parent").forEach(el => el.classList.remove("cc-active-parent"));
        if (!actionId) return;

        const sections = this.currentAppSections || [];
        const matchedId = searchMenuTree(sections, actionId, (m) => this.getMenuItemHref(m));

        if (matchedId) {
            const allEntries = navbar.querySelectorAll("[data-section]");
            for (const entry of allEntries) {
                if (String(entry.dataset.section) === String(matchedId)) {
                    const target = entry.closest("button") || entry.closest(".o_nav_entry") || entry;
                    target.classList.add("cc-active-parent");
                    break;
                }
            }
        }
    },

    onNavBarDropdownItemSelection(menu) {
        const result = super.onNavBarDropdownItemSelection(menu);
        setTimeout(() => this._ccHighlightParent(), 200);
        return result;
    },
});

function highlightChild() {
    const actionId = getActiveActionId();
    if (!actionId) return;
    const menus = document.querySelectorAll(".o-dropdown--menu");
    menus.forEach(menu => {
        menu.querySelectorAll(".cc-active-item").forEach(el => el.classList.remove("cc-active-item"));
        const items = menu.querySelectorAll(".dropdown-item, .o-dropdown-item, [href]");
        for (const item of items) {
            if (matchesAction(item.getAttribute("href") || "", actionId)) {
                item.classList.add("cc-active-item");
                break;
            }
        }
    });
}

setInterval(highlightChild, 250);
